#ifndef FLT_MAX
#define FLT_MAX 3.40282347e+38F
#endif

__attribute__((always_inline))
float euclid_dist_2(const float *pt1,
                    const float *pt2,
                    const int numdims)
{
    float ans = 0.0f;
    for (int i = 0; i < numdims; i++) {
        float diff = pt1[i] - pt2[i];
        ans += diff * diff;
    }
    return ans;
}

__attribute__((always_inline))
int find_nearest_point(const float *pt,
                       const int nfeatures,
                       const float *clusters,
                       const int nclusters)
{
    int index = 0;
    float min_dist = FLT_MAX;

    for (int i = 0; i < nclusters; i++) {
        float dist = euclid_dist_2(pt, clusters + (i * nfeatures), nfeatures);
        if (dist < min_dist) {
            min_dist = dist;
            index = i;
        }
    }
    return index;
}

void kmeans_clustering_kernel(const float *feature,
                              const int nfeatures,
                              const int npoints,
                              const int nclusters,
                              const float threshold,
                              int *membership,
                              float *clusters,
                              int *new_centers_len,
                              float *new_centers,
                              float *delta_ptr,
                              const int max_loop)
{
    int loop = 0;
    float delta;

    do {
        delta = 0.0f;

        for (int i = 0; i < npoints; i++) {
            int index = find_nearest_point(feature + (i * nfeatures),
                                           nfeatures,
                                           clusters,
                                           nclusters);

            if (membership[i] != index) {
                delta += 1.0f;
            }

            membership[i] = index;

            new_centers_len[index]++;
            for (int j = 0; j < nfeatures; j++) {
                new_centers[index * nfeatures + j] += feature[i * nfeatures + j];
            }
        }

        for (int i = 0; i < nclusters; i++) {
            if (new_centers_len[i] > 0) {
                for (int j = 0; j < nfeatures; j++) {
                    clusters[i * nfeatures + j] = new_centers[i * nfeatures + j] / (float)new_centers_len[i];
                    new_centers[i * nfeatures + j] = 0.0f;
                }
                new_centers_len[i] = 0;
            }
        }

        loop++;
    } while (delta > threshold && loop < max_loop);

    *delta_ptr = delta;
}
